// B14.8b: 2-node federation Playwright e2e suite + ts-net guard.
//
// Each test spins up its own pair of ddx-server processes (1 hub + 1 spoke)
// on loopback, both with --tsnet=false so no Tailscale dependency leaks
// in. Both nodes register as spokes against the hub (the hub uses the
// hub_spoke role) so the hub's /federation page lists both, and any
// ?scope=federation fan-out returns rows from both nodes.
//
// The "ts-net guard" tests use a separate hub bound to 0.0.0.0 with a
// non-loopback host IP discovered at runtime; the registration request is
// issued against that non-loopback IP so the hub's requireFederationTrusted
// gate sees a non-loopback RemoteAddr. If no non-loopback IPv4 is available
// (CI image without an external interface), the ts-net guard tests
// test.skip with a clear message — the loopback flows still cover the
// other AC items.

import { expect, request as playwrightRequest, test } from '@playwright/test';
import type { APIRequestContext } from '@playwright/test';
import { spawn, type ChildProcessWithoutNullStreams } from 'node:child_process';
import * as fs from 'node:fs';
import * as net from 'node:net';
import * as os from 'node:os';
import * as path from 'node:path';
import { fileURLToPath } from 'node:url';
import { ensureDdxE2EBinary } from './ddx-binary';

const FRONTEND_DIR = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const FIXTURE_DIR = path.resolve(FRONTEND_DIR, 'e2e/fixtures');

async function freePort(): Promise<number> {
	return new Promise((resolve, reject) => {
		const srv = net.createServer();
		srv.once('error', reject);
		srv.listen(0, '127.0.0.1', () => {
			const a = srv.address();
			if (!a || typeof a === 'string') {
				srv.close(() => reject(new Error('alloc port')));
				return;
			}
			const port = a.port;
			srv.close(() => resolve(port));
		});
	});
}

function copyFixture(): string {
	const root = fs.mkdtempSync(path.join(os.tmpdir(), 'ddx-fed-e2e-ws-'));
	const ent = (rel: string) => path.join(FIXTURE_DIR, rel);
	const dst = (rel: string) => path.join(root, rel);
	function walk(srcRel: string) {
		const stat = fs.statSync(ent(srcRel));
		if (stat.isDirectory()) {
			fs.mkdirSync(dst(srcRel), { recursive: true });
			for (const child of fs.readdirSync(ent(srcRel))) {
				walk(path.join(srcRel, child));
			}
		} else {
			fs.mkdirSync(path.dirname(dst(srcRel)), { recursive: true });
			fs.copyFileSync(ent(srcRel), dst(srcRel));
		}
	}
	for (const top of fs.readdirSync(FIXTURE_DIR)) {
		walk(top);
	}
	return root;
}

interface SpawnedServer {
	port: number;
	addr: string;
	baseURL: string;
	root: string;
	child: ChildProcessWithoutNullStreams;
	stdoutBuf: string;
	stderrBuf: string;
	api: APIRequestContext;
}

async function waitHealthy(api: APIRequestContext, child: ChildProcessWithoutNullStreams) {
	let last: unknown;
	for (let i = 0; i < 80; i++) {
		if (child.exitCode !== null) {
			throw new Error(`server exited early (${child.exitCode})`);
		}
		try {
			const r = await api.get('/api/health', { timeout: 500 });
			if (r.ok()) return;
		} catch (e) {
			last = e;
		}
		await new Promise((r) => setTimeout(r, 125));
	}
	throw new Error(`server not healthy: ${String(last)}`);
}

interface SpawnOpts {
	hubMode?: boolean;
	hubURL?: string;
	allowPlainHTTP?: boolean;
	bindAddr?: string;
	selfURL?: string;
	nodeName?: string;
	// When set, reuse this directory rather than copying the fixture again.
	// Required when restarting a spoke so the persisted identity_fingerprint
	// survives — otherwise the hub rejects the restart as a 409 duplicate
	// node_id.
	reuseRoot?: string;
}

async function spawnServer(opts: SpawnOpts): Promise<SpawnedServer> {
	const bin = ensureDdxE2EBinary();
	const port = await freePort();
	const bindAddr = opts.bindAddr ?? '127.0.0.1';
	const root = opts.reuseRoot ?? copyFixture();
	const args = ['server', '--port', String(port), '--addr', bindAddr, '--tsnet=false'];
	if (opts.hubMode) args.push('--hub-mode');
	if (opts.allowPlainHTTP) args.push('--federation-allow-plain-http');
	if (opts.hubURL) args.push('--hub-address', opts.hubURL);
	if (opts.selfURL) args.push('--federation-self-url', opts.selfURL);
	const child = spawn(bin, args, {
		cwd: root,
		env: {
			...process.env,
			DDX_NODE_NAME: opts.nodeName ?? `fed-e2e-${port}`,
			XDG_DATA_HOME: path.join(root, '.xdg-data'),
			XDG_CONFIG_HOME: path.join(root, '.xdg-config')
		}
	});
	const s: SpawnedServer = {
		port,
		addr: bindAddr,
		baseURL: `https://127.0.0.1:${port}`,
		root,
		child,
		stdoutBuf: '',
		stderrBuf: '',
		api: await playwrightRequest.newContext({
			baseURL: `https://127.0.0.1:${port}`,
			ignoreHTTPSErrors: true
		})
	};
	child.stdout.on('data', (d) => {
		s.stdoutBuf += d.toString();
	});
	child.stderr.on('data', (d) => {
		s.stderrBuf += d.toString();
	});
	await waitHealthy(s.api, child);
	return s;
}

async function stopServer(s: SpawnedServer, opts: { keepRoot?: boolean } = {}) {
	await s.api.dispose().catch(() => {});
	if (s.child.exitCode === null) {
		s.child.kill();
		await Promise.race([
			new Promise((r) => s.child.once('exit', r)),
			new Promise((r) =>
				setTimeout(() => {
					if (s.child.exitCode === null) s.child.kill('SIGKILL');
					r(undefined);
				}, 2500)
			)
		]);
	}
	if (!opts.keepRoot) fs.rmSync(s.root, { recursive: true, force: true });
}

async function nodeIdOf(s: SpawnedServer): Promise<string> {
	const r = await s.api.post('/graphql', {
		data: { query: '{ nodeInfo { id } }' }
	});
	const body = (await r.json()) as { data: { nodeInfo: { id: string } } };
	return body.data.nodeInfo.id;
}

async function federationNodes(
	s: SpawnedServer
): Promise<Array<{ nodeId: string; status: string; name: string }>> {
	const r = await s.api.post('/graphql', {
		data: {
			query: '{ federationNodes { nodeId status name } }'
		}
	});
	const body = (await r.json()) as {
		data: { federationNodes: Array<{ nodeId: string; status: string; name: string }> };
	};
	return body.data.federationNodes;
}

async function triggerFanOut(s: SpawnedServer): Promise<void> {
	// federatedBeads runs the fan-out path; the result is irrelevant — we
	// only need the side effect of StatusUpdates landing in the registry.
	await s.api.post('/graphql', {
		data: { query: '{ federatedBeads { nodeId } }' }
	});
}

function firstNonLoopbackIPv4(): string | null {
	const ifaces = os.networkInterfaces();
	for (const list of Object.values(ifaces)) {
		if (!list) continue;
		for (const a of list) {
			if (a.family === 'IPv4' && !a.internal) {
				// Skip docker bridges / link-local — pick the first usable.
				if (a.address.startsWith('169.254.')) continue;
				return a.address;
			}
		}
	}
	return null;
}

// ─── Federation 2-node tests ───────────────────────────────────────────────

test.describe('federation 2-node e2e', () => {
	test.setTimeout(150_000);

	test('hub /federation lists both nodes; scope=federation merges data; offline+restart cycle', async ({
		page
	}) => {
		const hub = await spawnServer({ hubMode: true, nodeName: 'fed-e2e-hub' });
		// Hub registers itself as a spoke (hub_spoke) so /federation lists it.
		await registerHubSelfAsSpoke(hub);

		const spoke = await spawnServer({
			hubURL: hub.baseURL,
			selfURL: '', // default
			nodeName: 'fed-e2e-spoke'
		});

		try {
			// Wait for both registrations to land in the hub registry.
			await expect
				.poll(async () => (await federationNodes(hub)).length, { timeout: 10_000 })
				.toBe(2);

			const fedNodes = await federationNodes(hub);
			const ids = new Set(fedNodes.map((n) => n.nodeId));
			expect(ids.has(await nodeIdOf(hub))).toBe(true);
			expect(ids.has(await nodeIdOf(spoke))).toBe(true);
			for (const n of fedNodes) {
				expect(['active', 'registered']).toContain(n.status);
			}

			// /federation page renders both nodes.
			await page.goto(`${hub.baseURL}/federation`);
			await expect(page.getByTestId('federation-page')).toBeVisible();
			const rows = page.getByTestId('federation-row');
			await expect(rows).toHaveCount(2);

			// Status badges reflect status (active OR registered before the
			// first heartbeat lands; both are healthy states).
			const badges = page.getByTestId('federation-status-badge');
			await expect(badges).toHaveCount(2);
			for (let i = 0; i < 2; i++) {
				const txt = (await badges.nth(i).textContent())?.trim().toLowerCase();
				expect(['active', 'registered']).toContain(txt);
			}

			// scope=federation fan-out combined view shows beads from BOTH
			// nodes. Each fixture workspace seeds 3 beads (fx-001/2/3); with
			// 2 federated nodes we expect 6 rows.
			const hubNodeId = await nodeIdOf(hub);
			await page.goto(`${hub.baseURL}/nodes/${hubNodeId}/beads?scope=federation`);
			await expect(page.getByTestId('scope-indicator')).toBeVisible();
			await expect(page.getByTestId('scope-toggle')).toContainText('federation');
			// Both fixture beads exist; expect at least one row per node by
			// their fixture title prefix.
			await expect
				.poll(async () => await page.getByText('Open ready bead').count(), { timeout: 10_000 })
				.toBeGreaterThanOrEqual(2);

			// Toggle switches LOCAL vs FEDERATION.
			await page.getByTestId('scope-toggle').click();
			await expect(page).not.toHaveURL(/scope=federation/);
			await expect(page.getByTestId('scope-indicator')).toHaveCount(0);
			// Local view still has 3 beads (fx-001/2/3).
			await expect(page.getByText('Open ready bead')).toBeVisible();

			// Stop the spoke process. Keep its root so the persisted
			// identity_fingerprint survives the restart cycle (re-registration
			// with a different fingerprint would trip the hub's 409 duplicate-
			// node_id guard).
			const spokeRoot = spoke.root;
			await stopServer(spoke, { keepRoot: true });
			// Close the hubAsSpoke too if it points at the spoke — it does
			// not, the hub registers itself; keep it running.

			await expect
				.poll(
					async () => {
						await triggerFanOut(hub);
						const ns = await federationNodes(hub);
						const found = ns.find((n) => n.name === 'fed-e2e-spoke');
						return found?.status ?? 'missing';
					},
					{ timeout: 15_000, intervals: [500, 1000, 1500] }
				)
				.toBe('offline');

			// /federation page reflects the offline badge for the spoke.
			await page.goto(`${hub.baseURL}/federation`);
			const offlineRow = page.locator('[data-testid="federation-row"][data-status="offline"]');
			await expect(offlineRow).toHaveCount(1);
			await expect(offlineRow.locator('[data-testid="federation-status-badge"]')).toContainText(
				/offline/i
			);

			// Restart the spoke — registration alone (handshake → StatusActive)
			// returns it to active without waiting on a heartbeat tick.
			const spoke2 = await spawnServer({
				hubURL: hub.baseURL,
				nodeName: 'fed-e2e-spoke',
				reuseRoot: spokeRoot
			});
			try {
				await expect
					.poll(
						async () => {
							const ns = await federationNodes(hub);
							const found = ns.find((n) => n.name === 'fed-e2e-spoke');
							return found?.status ?? 'missing';
						},
						{ timeout: 15_000, intervals: [500, 1000] }
					)
					.toMatch(/active|registered/);

				await page.goto(`${hub.baseURL}/federation`);
				const activeRows = page.locator(
					'[data-testid="federation-row"][data-status="active"], [data-testid="federation-row"][data-status="registered"]'
				);
				await expect(activeRows).toHaveCount(2);
			} finally {
				await stopServer(spoke2);
			}
		} finally {
			await stopServer(hub);
		}
	});
});

// Drive the hub to register itself as a spoke (hub_spoke role) via a direct
// loopback POST to /api/federation/register. This avoids spinning up a third
// process just to obtain a 2-row /federation listing.
async function registerHubSelfAsSpoke(hub: SpawnedServer): Promise<void> {
	const hubNodeId = await nodeIdOf(hub);
	const resp = await hub.api.post('/api/federation/register', {
		data: {
			node_id: hubNodeId,
			identity_fingerprint: 'hub-self-fp',
			name: 'fed-e2e-hub',
			url: hub.baseURL,
			ddx_version: '0.1.0',
			schema_version: '1',
			capabilities: ['beads', 'runs']
		}
	});
	if (!resp.ok()) throw new Error(`hub self-register failed: ${resp.status()}`);
}

package graphql_test

// Federation resolver integration tests (B14.6b). Exercises the four federated
// queries (federationNodes, federatedBeads, federatedRuns, federatedProjects)
// against two mock spoke servers. Verifies row shape, routing metadata, the
// partial-result rendering when one spoke is offline, and the version-skew
// rendering when one spoke is filtered by the handshake.

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/DocumentDrivenDX/ddx/internal/federation"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// stubFederation is a minimal FederationProvider backed by a fixed list of
// spokes and a real (in-process) FanOutClient pointed at httptest spoke
// servers.
type stubFederation struct {
	spokes []federation.SpokeRecord
	client *federation.FanOutClient
}

func (s *stubFederation) Spokes() []federation.SpokeRecord {
	out := make([]federation.SpokeRecord, len(s.spokes))
	copy(out, s.spokes)
	return out
}

func (s *stubFederation) FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error) {
	return s.client.Execute(ctx, s.spokes, req)
}

// newSpokeServer spins up an httptest server whose /graphql endpoint returns
// the canned JSON payload supplied by handler.
func newSpokeServer(t *testing.T, handlerFn func(req map[string]any) any) *httptest.Server {
	t.Helper()
	mux := http.NewServeMux()
	mux.HandleFunc("/graphql", func(w http.ResponseWriter, r *http.Request) {
		var body map[string]any
		_ = json.NewDecoder(r.Body).Decode(&body)
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(handlerFn(body))
	})
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	return srv
}

// newGQLHandlerWithFederation wires a minimal Resolver pointed at the supplied
// FederationProvider. The local query state provider is the same stub the
// other integration tests use, but no local data is exercised here.
func newGQLHandlerWithFederation(t *testing.T, fed ddxgraphql.FederationProvider) http.Handler {
	t.Helper()
	workDir, store := setupIntegrationDir(t)
	state := newTestStateProvider(workDir, store)
	gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers: &ddxgraphql.Resolver{
			State:      state,
			WorkingDir: workDir,
			Actions:    testActionDispatcher{},
			Federation: fed,
		},
		Directives: ddxgraphql.DirectiveRoot{},
	}))
	gqlSrv.AddTransport(transport.POST{})
	return gqlSrv
}

// TestFederation_QueryShape_TwoHealthySpokes exercises all four federated
// queries against two mock spokes, both healthy, and verifies that each
// returned row carries the routing metadata (nodeId, projectId, projectUrl,
// writeCapability, status) along with the typed payload shape.
func TestFederation_QueryShape_TwoHealthySpokes(t *testing.T) {
	skipIntegrationInShort(t)
	now := time.Date(2026, 5, 2, 12, 0, 0, 0, time.UTC)

	spoke1 := newSpokeServer(t, func(req map[string]any) any {
		// Same canned response for any query — body is asserted by the
		// resolver decode path, not by query string.
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-A1", "title": "spoke1 bead", "status": "open",
						"priority": 0, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p1",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-1", "layer": "run", "status": "success",
						"projectID": "p1", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p1", "name": "spoke1-proj", "path": "/tmp/p1",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})
	spoke2 := newSpokeServer(t, func(req map[string]any) any {
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-B1", "title": "spoke2 bead", "status": "open",
						"priority": 1, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p2",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-2", "layer": "run", "status": "running",
						"projectID": "p2", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p2", "name": "spoke2-proj", "path": "/tmp/p2",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})

	fed := &stubFederation{
		client: federation.NewFanOutClient(),
		spokes: []federation.SpokeRecord{
			{
				NodeID: "node-spoke1", Name: "spoke1", URL: spoke1.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "@identity:abc"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
			{
				NodeID: "node-spoke2", Name: "spoke2", URL: spoke2.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "write"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
		},
	}
	fed.client.HubDDxVersion = "0.1.0"
	fed.client.HubSchemaVersion = federation.CurrentSchemaVersion
	fed.client.PerNodeTimeout = 2 * time.Second

	h := newGQLHandlerWithFederation(t, fed)

	// federationNodes: surface should match spoke registry; @identity:* is
	// stripped; writeCapability flips per-spoke; lastHeartbeat is non-null
	// because the registry has a heartbeat timestamp.
	respNodes := gqlPost(t, h, `{ federationNodes {
		id nodeId name url status ddxVersion schemaVersion
		capabilities registeredAt lastHeartbeat writeCapability lastError
	} }`)
	var nodesData struct {
		FederationNodes []struct {
			ID              string   `json:"id"`
			NodeID          string   `json:"nodeId"`
			Name            string   `json:"name"`
			URL             string   `json:"url"`
			Status          string   `json:"status"`
			DdxVersion      string   `json:"ddxVersion"`
			SchemaVersion   string   `json:"schemaVersion"`
			Capabilities    []string `json:"capabilities"`
			RegisteredAt    string   `json:"registeredAt"`
			LastHeartbeat   *string  `json:"lastHeartbeat"`
			WriteCapability bool     `json:"writeCapability"`
			LastError       *string  `json:"lastError"`
		} `json:"federationNodes"`
	}
	if err := json.Unmarshal(respNodes["data"], &nodesData); err != nil {
		t.Fatalf("unmarshal nodes: %v", err)
	}
	if len(nodesData.FederationNodes) != 2 {
		t.Fatalf("want 2 federation nodes, got %d", len(nodesData.FederationNodes))
	}
	for _, n := range nodesData.FederationNodes {
		for _, c := range n.Capabilities {
			if len(c) > 0 && c[0] == '@' {
				t.Errorf("synthetic capability %q leaked through, expected filtered", c)
			}
		}
		if n.LastHeartbeat == nil {
			t.Errorf("node %s: expected non-null lastHeartbeat", n.NodeID)
		}
	}
	if got := nodesData.FederationNodes[0].WriteCapability; got != false {
		t.Errorf("spoke1 writeCapability: want false, got %v", got)
	}
	if got := nodesData.FederationNodes[1].WriteCapability; got != true {
		t.Errorf("spoke2 writeCapability: want true, got %v", got)
	}

	// federatedBeads: one row per spoke; each row carries projectUrl ==
	// spoke URL and the bead nested payload.
	respBeads := gqlPost(t, h, `{ federatedBeads {
		nodeId projectId projectUrl writeCapability status bead { id title status projectID }
	} }`)
	var beadsData struct {
		FederatedBeads []struct {
			NodeID          string  `json:"nodeId"`
			ProjectID       *string `json:"projectId"`
			ProjectURL      string  `json:"projectUrl"`
			WriteCapability bool    `json:"writeCapability"`
			Status          string  `json:"status"`
			Bead            struct {
				ID        string  `json:"id"`
				Title     string  `json:"title"`
				Status    string  `json:"status"`
				ProjectID *string `json:"projectID"`
			} `json:"bead"`
		} `json:"federatedBeads"`
	}
	if err := json.Unmarshal(respBeads["data"], &beadsData); err != nil {
		t.Fatalf("unmarshal beads: %v", err)
	}
	if len(beadsData.FederatedBeads) != 2 {
		t.Fatalf("want 2 federated beads, got %d", len(beadsData.FederatedBeads))
	}
	seenURL := map[string]bool{spoke1.URL: false, spoke2.URL: false}
	for _, fb := range beadsData.FederatedBeads {
		if _, ok := seenURL[fb.ProjectURL]; !ok {
			t.Errorf("unexpected projectUrl %q", fb.ProjectURL)
		}
		seenURL[fb.ProjectURL] = true
		if fb.ProjectID == nil || *fb.ProjectID == "" {
			t.Errorf("row %s: expected non-empty projectId", fb.NodeID)
		}
		if fb.Bead.ID == "" {
			t.Errorf("row %s: expected non-empty bead.id", fb.NodeID)
		}
	}
	for url, hit := range seenURL {
		if !hit {
			t.Errorf("expected a federated row for spoke URL %s", url)
		}
	}

